keyframes_css:
@keyframes fall {
  0% {
    transform: translateY(-20px);
    opacity: 1;
  }
  100% {
    transform: translateY(180px);
    opacity: 0;
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #1a1a2e 0%, #16213e 100%);
  border-radius: 8px;
  overflow: hidden;
  position: relative;
}

.demo-stage::before,
.demo-stage::after {
  content: '';
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  animation: fall 1.5s infinite ease-in;
}

.demo-stage::before {
  left: 30%;
  animation-delay: 0s;
}

.demo-stage::after {
  left: 60%;
  animation-delay: 0.5s;
}

.demo-stage .drop1 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 45%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 1s;
}

.demo-stage .drop2 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 75%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.25s;
}

.demo-stage .drop3 {
  position: absolute;
  width: 3px;
  height: 3px;
  background: #64b5f6;
  border-radius: 50%;
  left: 15%;
  animation: fall 1.5s infinite ease-in;
  animation-delay: 0.75s;
}
